#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int n;
    scanf("%d", &n);
    int sausages[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &sausages[i]);
    }
    qsort(sausages, n, sizeof(int), compare);
    printf("%d\n", n);
    return 0;
}

