code.Java:
import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] sausages = new int[n];
        for (int i = 0; i < n; i++) {
            sausages[i] = scanner.nextInt();
        }
        Arrays.sort(sausages);
        System.out.println(n);
    }
}

code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let sausages;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        sausages = input.split(' ').map(Number);
        sausages.sort((a, b) => a - b);
        console.log(n);
        rl.close();
    }
});

